package org.eclipse.rdf4j.query.algebra.equivalence;

/** Conservative lower and upper bounds for the number of result occurrences. */
public final class CardinalityBounds {
	public static final long UNBOUNDED = -1L;

	private final long minimum;
	private final long maximum;

	public CardinalityBounds(long minimum, long maximum) {
		if (minimum < 0) {
			throw new IllegalArgumentException("minimum must be non-negative");
		}
		if (maximum != UNBOUNDED && maximum < minimum) {
			throw new IllegalArgumentException("maximum must be unbounded or at least minimum");
		}
		this.minimum = minimum;
		this.maximum = maximum;
	}

	public long minimum() {
		return minimum;
	}

	public long maximum() {
		return maximum;
	}

	public boolean hasFiniteMaximum() {
		return maximum != UNBOUNDED;
	}

	@Override
	public String toString() {
		return "[" + minimum + ", " + (maximum == UNBOUNDED ? "∞" : maximum) + "]";
	}
}
